<script setup>
import { onMounted, reactive, ref } from 'vue'; import { useRoute } from 'vue-router'
import AsyncState from '../../../components/admin/AsyncState.vue'; import PageActions from '../../../components/admin/PageActions.vue'; import { taskApi } from '../../../lib/taskApi.js'; import { operationId } from '../../../lib/apiUtils.js'
const route=useRoute(),task=ref(null),taskVersion=ref(null),items=ref([]),loading=ref(false),error=ref(''),notice=ref(''),selected=ref(new Set()),targetStatus=ref('COMPLETED'),importFile=ref(null),job=ref(null)
const itemForm=reactive({externalItemId:'',referenceText:'',referenceAudioUrl:'',referenceVideoUrl:''})
async function load(){loading.value=true;error.value='';try{const [taskData,versions,itemResult]=await Promise.all([taskApi.get(route.params.id),taskApi.versions(route.params.id),taskApi.items(route.params.id,0,100)]);task.value=taskData;taskVersion.value=versions.find(v=>v.id===taskData.currentVersionId);items.value=itemResult.items||[]}catch(e){error.value=e.message}finally{loading.value=false}}
async function add(){try{await taskApi.addItem(route.params.id,{...itemForm},operationId('item-add'));Object.keys(itemForm).forEach(k=>itemForm[k]='');await load()}catch(e){error.value=e.message}}
async function upload(){if(!importFile.value)return;try{job.value=await taskApi.importItems(route.params.id,importFile.value,operationId('import'));notice.value=`导入任务 ${job.value.importJobId} 已进入队列`}catch(e){error.value=e.message}}
async function refreshJob(){if(job.value?.importJobId)job.value=await taskApi.importJob(job.value.importJobId)}
async function itemAction(row,action){if(!confirm(`确认${action==='discard'?'废弃':'恢复'}条目 ${row.itemCode}？`))return;try{await taskApi[action](row.id,operationId(`item-${action}`),row.revision);await load()}catch(e){error.value=e.message}}
function toggle(row){const next=new Set(selected.value);next.has(row.id)?next.delete(row.id):next.add(row.id);selected.value=next}
async function batch(action){if(!selected.value.size||!confirm(`确认批量执行 ${action}，共 ${selected.value.size} 条？`))return;const commands=items.value.filter(r=>selected.value.has(r.id)).map(r=>({itemId:r.id,expectedRevision:r.revision}));try{const result=await taskApi.batchAction(action,commands,operationId(`batch-${action}`));notice.value=`批量操作完成：成功 ${result.filter(r=>r.success).length}，冲突 ${result.filter(r=>!r.success).length}`;selected.value=new Set();await load()}catch(e){error.value=e.message}}
async function changeStatus(){if(!selected.value.size||!confirm(`确认将 ${selected.value.size} 条数据调整为 ${targetStatus.value}？`))return;const commands=items.value.filter(r=>selected.value.has(r.id)).map(r=>({itemId:r.id,expectedRevision:r.revision,collectorId:r.collectorId}));try{const result=await taskApi.batchStatus(targetStatus.value,commands,operationId('batch-status'));notice.value=`状态调整完成：成功 ${result.filter(r=>r.success).length}，冲突 ${result.filter(r=>!r.success).length}`;selected.value=new Set();await load()}catch(e){error.value=e.message}}
onMounted(load)
</script>
<template><section class="admin-page"><PageActions :title="task?.name||'任务详情'" :description="task?`${task.taskCode} · v${task.currentVersionNumber} · ${task.lifecycle}`:''"><router-link class="button-secondary" :to="`/admin/tasks/${route.params.id}/edit`">修改结构</router-link><router-link class="button-primary" :to="`/admin/tasks/${route.params.id}/permissions`">采集权限</router-link></PageActions><AsyncState :loading="loading" :error="error" :empty="!task" @retry="load"><div class="business-grid"><form class="business-card business-form" @submit.prevent="add"><h3>添加池数据</h3><label>外部编号<input v-model.trim="itemForm.externalItemId" /></label><label>参考文字<textarea v-model.trim="itemForm.referenceText" rows="4" /></label><label>参考音频 URL<input v-model.trim="itemForm.referenceAudioUrl" type="url" /></label><label>参考视频 URL<input v-model.trim="itemForm.referenceVideoUrl" type="url" /></label><p class="business-note">三种参考源至少填写一项；远程 URL 由后端安全下载。</p><button class="button-primary">添加</button><hr/><h3>批量导入</h3><input type="file" accept=".csv,.xlsx" @change="importFile=$event.target.files[0]"/><button type="button" class="button-primary" @click="upload">开始导入</button><div v-if="job" class="business-note">状态：{{ job.status }} <button type="button" class="button-link" @click="refreshJob">刷新</button><button v-if="['PARTIAL_SUCCESS','FAILED'].includes(job.status)" type="button" class="button-link" @click="taskApi.retryImport(job.importJobId,operationId('import-retry')).then(v=>job=v)">重试失败行</button></div><p v-if="notice" class="business-success">{{ notice }}</p></form><div class="business-card business-card-wide"><div class="business-heading"><h3>数据池（{{ items.length }}）</h3><div class="business-actions"><select v-model="targetStatus"><option value="RECORDING_PENDING">待录制</option><option v-if="taskVersion?.humanReviewEnabled" value="REVIEW_PENDING">待审核</option><option value="COMPLETED">已完成</option></select><button class="button-secondary" :disabled="!selected.size" @click="changeStatus">调整状态</button><button class="button-secondary" :disabled="!selected.size" @click="batch('release')">批量释放</button><button class="button-secondary is-danger" :disabled="!selected.size" @click="batch('discard')">批量废弃</button><button class="button-secondary" :disabled="!selected.size" @click="batch('restore')">批量恢复</button></div></div><AsyncState :loading="false" :error="''" :empty="!items.length"><div class="business-table-wrap"><table class="business-table"><thead><tr><th>选择</th><th>编号</th><th>外部编号</th><th>状态</th><th>采集员</th><th>结果</th><th>操作</th></tr></thead><tbody><tr v-for="row in items" :key="row.id"><td><input type="checkbox" :checked="selected.has(row.id)" @change="toggle(row)"/></td><td>{{ row.itemCode }}</td><td>{{ row.externalItemId||'-' }}</td><td>{{ row.status }}</td><td>{{ row.collectorId||'-' }}</td><td>{{ row.currentResult?.audio?.durationMillis ? `${Math.round(row.currentResult.audio.durationMillis/1000)}秒` : row.currentResult?.text ? '文字' : '-' }}</td><td><button v-if="row.status!=='DISCARDED'" class="button-link is-danger" @click="itemAction(row,'discard')">废弃</button><button v-else class="button-link" @click="itemAction(row,'restore')">恢复</button><router-link class="button-link" :to="`/admin/items/${row.id}/operations`">记录</router-link></td></tr></tbody></table></div></AsyncState></div></div></AsyncState></section></template>
